vulnerable.code:
/* VULNERABLE: gets() has no length limit — removed from C11 standard */
#include <stdio.h>

void process_input(void) {
    char buffer[64];     /* 64 bytes on the stack */
    gets(buffer);        /* reads until newline — no length check */
    printf("Input: %s\n", buffer);
}

/* Input of 100 bytes:
   - Bytes 1-64: fill the buffer
   - Bytes 65-72: overwrite saved frame pointer
   - Bytes 73-80: overwrite return address
   - Remaining: shellcode or ROP gadget addresses */

secure.code:
/* SECURE: fgets() with explicit size limit */
#include <stdio.h>
#include <string.h>

void process_input(void) {
    char buffer[64];

    /* fgets(dest, max_chars_including_null, stream) */
    /* Will read at most sizeof(buffer)-1 characters */
    if (fgets(buffer, sizeof(buffer), stdin) == NULL) {
        /* Handle EOF or error */
        return;
    }

    /* Remove trailing newline if present */
    buffer[strcspn(buffer, "\n")] = '\0';

    printf("Input: %s\n", buffer);
}

/* Even with 1000 bytes of input, fgets stops at 63 chars */

vulnerable.code:
/* VULNERABLE: strcpy has no length check */
#include <string.h>

void copy_name(const char *user_input) {
    char name[32];
    strcpy(name, user_input);  /* copies until null byte — no limit */
    use_name(name);
}

/* Also vulnerable:
   strcat(dest, src)      — no length check on append
   sprintf(buf, fmt, ...) — no buffer size limit
   scanf("%s", buf)       — reads until whitespace, no limit */

secure.code:
/* SECURE: use length-limited alternatives */
#include <string.h>

void copy_name(const char *user_input) {
    char name[32];

    /* strncpy copies at most n bytes */
    strncpy(name, user_input, sizeof(name) - 1);
    name[sizeof(name) - 1] = '\0';  /* ensure null termination */

    use_name(name);
}

/* Modern alternatives (Annex K / MSVC):
   strcpy_s(dest, dest_size, src)     — safe copy
   strncat_s(dest, dest_size, src, n) — safe append
   snprintf(buf, sizeof(buf), fmt, ...) — safe format */

